queries.sparql:
PREFIX : <http://ambrosia.example.org/student#>
PREFIX p: <http://ambrosia.example.org/student/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?fullname ?field_of_study WHERE {
  ?students a :Students .
  OPTIONAL { ?students p:name ?fullname . }
  OPTIONAL { ?students p:Field_Of_Study ?field_of_study . }
  ?students p:BirthDate ?birthdate_s .
  FILTER(xsd:double(SUBSTR(STR(?birthdate_s), 1, 4)) > 1990)
}

